const uploadDate = $('Webhook').first().json.body.uploadDate;
const uuid = $('Webhook').first().json.body.uuid;
const sn = $('Webhook').first().json.body.sn;
const cplc = $('Webhook').first().json.body.cplc;
const id = $('Webhook').first().json.body.id;
const procedure_name = 
$('Webhook').first().json.body.procedure_name
// 使用正则替换所有换行符（\n、\r）为空字符串
const cleanSn = sn.replace(/\s/g, '');
const cleanUuid = uuid.replace(/\s/g, '');
const cleanProcedure_name = procedure_name.replace(/\s/g, '');

// 返回清理后的数据
return {
  json: {
    body: {
      uploadDate:uploadDate,
      uuid:cleanUuid,
      sn: cleanSn,
      cplc: cplc,
      id:id,
      procedure_name: cleanProcedure_name
    }
  }
};

